            invariant
                0 <= x && x <= y && y < a.len(),
                m == x || m == y,
                forall|i: int| 0 <= i && i < x ==> a[i] <= a[m as int],
                forall|i: int| y < i && i < a.len() ==> a[i] <= a[m as int],
         decreases 
            y - x
    {
        if a[x] <= a[y] {
            x = x + 1;
            m = y;
        } else {
            y = y - 1;
            m = x;
        }
    }

    x
}

