        invariant
            0 <= i && i <= a.len() / 2,
            result.len() == i,
            forall|k: int| 0 <= k < i ==> result[k] == a[2 * k] + a[2 * k + 1],
        decreases
            a.len()/2-i
    {
        let sum = a[2 * i] + a[2 * i + 1];
        result.push(sum);
        i += 1;
    }

    result
