                assert(ghost_groups.flatten() + current_group@ =~= remove_nonparens(
                    input@.take((pos + 1) as int),
                ));
            }
        }
    }
    assert(input@.take(input_len as int) =~= input@);
    assert(ghost_groups.flatten() + current_group@ == ghost_groups.flatten());
    groups
