        =~= string.skip(1).subrange(0, substring.skip(1).len() as int))) {
        assert forall|i: int| 0 <= i < substring.len() implies #[trigger] substring[i]
            == string.subrange(0, substring.len() as int)[i] by {
            if i == 0 {
