        invariant
            num_overflows <= k,
            max_plus == i32::MAX + 1,
            s >= 0,
            s + num_overflows * max_plus == sum(first_n(operations@, k as int)),
            forall|i: int| 0 <= i <= k ==> #[trigger] sum(first_n(operations@, i)) >= 0,
