    while index < str1.len()
        invariant
            0 <= index <= str1.len(),
            toggle_case.len() == index,
            forall|i: int|
                0 <= i < index ==> toggle_case[i] == to_toggle_case_spec(#[trigger] str1[i]),
        decreases
