    let mut high: usize = a.len();

    while low < high
        invariant
            0 <= low as int <= high as int <= a.len() as int,
            forall|i: int| 0 <= i < low as int ==> a[i] < key,
            forall|i: int| high as int <= i < a.len() as int ==> a[i] >= key,
            forall|i: int, j: int| 0 <= i < j < a.len() as int ==> a[i] <= a[j],
