            assert(eval(*e1, s) == n1);
            assert(*e2 == e2_inner);
            assert(eval(mult_exp, s) == eval(*e1, s) * eval(*e2, s));
            assert(eval(mult_exp, s) == n1 * eval(*e2, s));
            assert(eval(mult_exp, s) == 1 * eval(*e2, s));
