                    58  //ASCII -> colon=58

                } else {
                    str1[k]
                }),
        decreases
            str1.len() - index
    {
        if ((str1[index] == 32) || (str1[index] == 44) || (str1[index] == 46)) {
            result.push(58);  //ASCII -> colon=58
        } else {
